 function current(){return routes[hash()]||hash();}
 function go(path){location.hash=path;}
 function notice(message,kind='info'){global.toast?.(message);const node=document.getElementById('erp-live');if(node){node.textContent=message;node.dataset.kind=kind;}}
 function top(title,actions=''){return`<div class="topbar erp-top"><div><h1>${e(title)}</h1><p class="erp-subtitle">Données de l’entreprise connectée</p></div><div class="actions">${actions}</div></div><div id="erp-live" class="sr-only" aria-live="polite"></div>`;}
 function empty(title,text,action=''){return`<div class="phase1-empty"><b>${e(title)}</b><span>${e(text)}</span>${action}</div>`;}
 function status(value){const key=String(value||'draft').toLowerCase(),cls=['validated','confirmed','active','paid','received'].includes(key)?'ok':['cancelled','archived','rejected','overdue'].includes(key)?'danger':['sent','partial','counted','pending'].includes(key)?'warn':'info';return`<span class="phase1-status ${cls}">${e(key.replaceAll('_',' '))}</span>`;}
 function button(label,handler,kind='btn-o',attrs=''){return`<button class="btn ${kind}" onclick="${handler}" ${attrs}>${e(label)}</button>`;}
 async function load(force=false){
  if(state.loading||state.loaded&&!force)return;state.loading=true;state.error='';
  try{state.companyId=await api().companyContext();const cid=encodeURIComponent(state.companyId),catalogColumns='id,company_id,item_type,reference,barcode,name,short_description,sales_description,category,subcategory,brand,unit,image_path,sale_price,tax_rate,minimum_price,stock_managed,minimum_stock,maximum_stock,reorder_point,valuation_method,active,created_by,created_at,updated_at',documentColumns='id,company_id,document_type,number,version,client_id,supplier_id,status,issue_date,due_date,subject,client_reference,currency,language,payment_terms,payment_method,internal_notes,public_notes,discount_rate,total_excl_tax,total_tax,total_incl_tax,source_document_id,validated_at,archived_at,created_by,created_at,updated_at,sale_type,opportunity_id,assigned_user_id,template_id,deposit_rate,metadata',lineColumns='id,company_id,document_id,position,line_type,section_id,item_id,reference,name,description,quantity,unit,unit_price,discount_rate,tax_rate,optional,total_excl_tax,total_tax,total_incl_tax,created_by,created_at,updated_at',movementColumns='id,company_id,item_id,movement_type,quantity,unit,from_warehouse_id,from_location_id,to_warehouse_id,to_location_id,occurred_at,source_type,source_id,reason,comment,attachment_path,reversal_of,status,created_by,created_at,updated_at',queries={
    settings:`company_settings?select=*&company_id=eq.${cid}`,docSettings:`company_document_settings?select=*&company_id=eq.${cid}`,erpSettings:`company_erp_settings?select=*&company_id=eq.${cid}`,sequences:`document_sequences?select=*&company_id=eq.${cid}&order=document_type`,addresses:`company_addresses?select=*&company_id=eq.${cid}&order=created_at`,members:`company_members?select=*&company_id=eq.${cid}`,logos:`company_logos?select=*&company_id=eq.${cid}&is_active=eq.true&order=created_at.desc`,clients:`clients?select=*&company_id=eq.${cid}&order=created_at.desc`,suppliers:`suppliers?select=*&company_id=eq.${cid}&order=created_at.desc`,supplierItems:`supplier_items?select=*&company_id=eq.${cid}`,opportunities:`opportunities?select=*&company_id=eq.${cid}&order=created_at.desc`,
    catalog:`catalog_items?select=${catalogColumns}&company_id=eq.${cid}&order=name`,documents:`documents?select=${documentColumns},client:clients(id,legal_name,first_name,last_name)&company_id=eq.${cid}&order=created_at.desc`,
    lines:`document_lines?select=${lineColumns}&company_id=eq.${cid}&order=position`,templates:`document_templates?select=*&company_id=eq.${cid}&order=updated_at.desc`,
    warehouses:`warehouses?select=*&company_id=eq.${cid}&order=name`,locations:`warehouse_locations?select=*&company_id=eq.${cid}&order=code`,
    levels:`stock_levels?select=*&company_id=eq.${cid}`,movements:`stock_movements?select=${movementColumns},item:catalog_items(name,reference)&company_id=eq.${cid}&order=occurred_at.desc&limit=300`,
    reservations:`stock_reservations?select=*&company_id=eq.${cid}`,inventories:`inventory_counts?select=*&company_id=eq.${cid}&order=created_at.desc`,inventoryLines:`inventory_count_lines?select=*&company_id=eq.${cid}`,
    purchaseOrders:`purchase_orders?select=*,supplier:suppliers(legal_name)&company_id=eq.${cid}&order=created_at.desc`,purchaseOrderLines:`purchase_order_lines?select=*&company_id=eq.${cid}`,receipts:`goods_receipts?select=*&company_id=eq.${cid}&order=created_at.desc`,deliveries:`deliveries?select=*&company_id=eq.${cid}&order=created_at.desc`,deliveryLines:`delivery_lines?select=*&company_id=eq.${cid}`,
    payments:`payments?select=*&company_id=eq.${cid}`,costHistory:`stock_cost_history?select=*&company_id=eq.${cid}&order=created_at.desc`,
    supplierRequests:`supplier_quote_requests?select=*,supplier:suppliers(legal_name)&company_id=eq.${cid}&order=created_at.desc`,supplierReturns:`supplier_returns?select=*,supplier:suppliers(legal_name)&company_id=eq.${cid}&order=created_at.desc`
   };const entries=await Promise.all(Object.entries(queries).map(async([key,path])=>{try{return[key,await api().request('/rest/v1/'+path)];}catch(error){return[key,[]];}}));state.data=Object.fromEntries(entries);let financial={};try{financial=await api().rpc('get_company_financial_fields',{target_company_id:state.companyId})||{};}catch{}for(const [dataKey,financialKey] of [['catalog','catalog'],['documents','documents'],['lines','lines'],['movements','movements']]){const values=new Map((financial[financialKey]||[]).map(row=>[row.id,row]));state.data[dataKey]=(state.data[dataKey]||[]).map(row=>Object.assign(row,values.get(row.id)||{}));}state.data.logoUrls={};await Promise.all((state.data.logos||[]).map(async logo=>{try{const signed=await api().signedUrl('company-assets',logo.storage_path,3600);state.data.logoUrls[logo.variant]=signed.signedURL||signed.signedUrl||'';}catch{}}));state.loaded=true;
  }catch(error){state.error=error.message;}finally{state.loading=false;}
 }
 function navGroup(title,icon,items){const active=items.some(item=>hash()===item[0]);return`<div class="phase1-group"><div class="phase1-group-head ${active?'on':''}"><span>${icon}</span><span class="lbl">${e(title)}</span></div><div class="phase1-subtabs">${items.map(([path,label])=>`<button class="phase1-subtab ${hash()===path?'on':''}" onclick="PilozApp.go('${path}')"><span>${e(label)}</span></button>`).join('')}</div></div>`;}
 function renderNav(){const node=document.getElementById('tabs');if(!node)return;node.innerHTML=`
  <button class="tab ${hash()==='dashboard'?'on':''}" onclick="PilozApp.go('dashboard')"><span>⌂</span><span class="lbl">Tableau de bord</span></button>
  ${navGroup('Ventes','€',[['sales/quotes','Devis'],['sales/invoices','Factures'],['sales/deposit-invoices','Factures d’acompte'],['sales/credit-notes','Avoirs'],['sales/orders','Commandes'],['sales/contracts','Contrats'],['sales/reminders','Relances'],['sales/statements','Relevés clients'],['sales/clients','Clients'],['sales/catalog','Articles & services']])}
  ${navGroup('Stock','▦',[['stock/overview','Vue d’ensemble'],['stock/items','Articles stockés'],['stock/movements','Mouvements'],['stock/inventories','Inventaires'],['stock/entries','Entrées'],['stock/exits','Sorties'],['stock/transfers','Transferts'],['stock/reservations','Réservations'],['stock/alerts','Alertes'],['stock/warehouses','Entrepôts'],['stock/locations','Emplacements'],['stock/replenishment','Approvisionnements']])}
  ${navGroup('Achats','↙',[['purchases/suppliers','Fournisseurs'],['purchases/requests','Demandes de prix'],['purchases/orders','Commandes fournisseurs'],['purchases/receipts','Réceptions'],['purchases/returns','Retours fournisseurs']])}
  <button class="tab ${hash()==='templates'?'on':''}" onclick="PilozApp.go('templates')"><span>▤</span><span class="lbl">Modèles</span></button>
  <button class="tab ${hash()==='reports'?'on':''}" onclick="PilozApp.go('reports')"><span>▥</span><span class="lbl">Rapports</span></button>
  <button class="tab ${hash()==='settings'?'on':''}" onclick="PilozApp.go('settings')"><span>⚙</span><span class="lbl">Paramètres</span></button>`;}
 async function render(){renderNav();const main=document.getElementById('main');if(!main)return;if(!global.PilozRuntime?.session){return;}if(!state.loaded){main.innerHTML=top('Chargement')+'<div class="erp-loading">Chargement des données sécurisées…</div>';await load();}
  if(state.error){main.innerHTML=top('Connexion aux données')+empty('Données ERP indisponibles',state.error,button('Réessayer','PilozApp.refresh()','btn-p'));return;}
  document.documentElement.classList.toggle('erp-no-costs',!allowed('view_purchase_prices'));
  document.documentElement.classList.toggle('erp-no-margins',!allowed('view_margins'));
  document.documentElement.classList.toggle('erp-no-stock-adjustment',!allowed('adjust_stock'));
  const route=current();if(route==='dashboard')renderDashboard();else if(route.startsWith('documents:'))renderDocuments(route.split(':')[1]);else if(route==='document-editor'){renderDocumentEditor();setTimeout(enhanceDocumentActions,0);}else if(route==='clients')renderPartners('clients');else if(route==='suppliers')renderPartners('suppliers');else if(route==='catalog')renderCatalog();else if(route==='templates')renderTemplates();else if(route==='template-editor')renderTemplateEditor();else if(route==='stock')renderStock();else if(route.startsWith('stock-movements'))renderMovements(route.split(':')[1]);else if(route==='stock-reservations')renderReservations();else if(route==='warehouses')renderWarehouses();else if(route==='inventories')renderInventories();else if(route==='stock-alerts')renderAlerts();else if(route==='supplier-requests')renderSupplierRequests();else if(route==='purchase-orders')renderPurchaseOrders();else if(route==='receipts')renderReceipts();else if(route==='supplier-returns')renderSupplierReturns();else if(route==='reports')renderReports();else if(route==='settings'){renderSettings();setTimeout(enhancePhoneVerification,0);}else main.innerHTML=top('Module')+empty('Module introuvable','Cette vue n’existe pas.');
 }
 async function refresh(){state.loaded=false;await load(true);render();}
 function renderDashboard(){const d=state.data,docs=d.documents||[],quotes=docs.filter(x=>x.document_type==='quote'),invoices=docs.filter(x=>x.document_type==='invoice'),outstanding=invoices.filter(x=>!['paid','cancelled'].includes(x.status)).reduce((s,x)=>s+Number(x.total_incl_tax||0),0),alerts=stockAlerts();document.getElementById('main').innerHTML=top('Tableau de bord',button('Actualiser','PilozApp.refresh()'))+`<div class="erp-kpis"><article><span>Devis</span><b>${quotes.length}</b></article><article><span>Factures</span><b>${invoices.length}</b></article><article><span>À encaisser</span><b>${money(outstanding)}</b></article><article><span>Alertes stock</span><b>${alerts.length}</b></article></div><div class="erp-grid-2"><section class="phase1-card"><h2>Derniers documents</h2>${docs.slice(0,8).map(x=>`<button class="erp-row-button" onclick="PilozApp.editDocument('${x.id}')"><span><b>${e(x.number||'Brouillon')}</b><small>${e(x.subject||labels[x.document_type]||x.document_type)}</small></span><strong>${money(x.total_incl_tax)}</strong></button>`).join('')||'<p>Aucun document.</p>'}</section><section class="phase1-card"><h2>À traiter</h2>${alerts.slice(0,8).map(x=>`<div class="erp-alert"><b>${e(x.item.name)}</b><span>${e(x.message)}</span></div>`).join('')||'<p>Aucune alerte de stock.</p>'}</section></div>`;}
 function renderDocuments(type){const rows=(state.data.documents||[]).filter(x=>x.document_type===type),showCost=allowed('view_purchase_prices'),showMargin=allowed('view_margins');document.getElementById('main').innerHTML=top(labels[type]||'Documents',button('Nouveau','PilozApp.newDocument(\''+type+'\')','btn-p'))+(rows.length?`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><thead><tr><th>Numéro</th><th>Client / objet</th><th>Date</th><th>Échéance</th><th>HT</th><th>TTC</th>${showCost?'<th>Coût</th>':''}${showMargin?'<th>Marge</th>':''}<th>Statut</th></tr></thead><tbody>${rows.map(row=>`<tr tabindex="0" onclick="PilozApp.editDocument('${row.id}')"><td class="phase1-mono"><b>${e(row.number||'Brouillon')}</b></td><td>${e(row.client?.legal_name||[row.client?.first_name,row.client?.last_name].filter(Boolean).join(' ')||'—')}<small>${e(row.subject||'')}</small></td><td>${date(row.issue_date)}</td><td>${date(row.due_date)}</td><td>${money(row.total_excl_tax)}</td><td><b>${money(row.total_incl_tax)}</b></td>${showCost?`<td>${money(row.total_cost)}</td>`:''}${showMargin?`<td>${money(Number(row.total_excl_tax)-Number(row.total_cost))}</td>`:''}<td>${status(row.status)}</td></tr>`).join('')}</tbody></table></div>`:empty(`Aucun ${labels[type]?.toLowerCase()||'document'}`,'Créez votre premier document.',button('Créer','PilozApp.newDocument(\''+type+'\')','btn-p')));}
 function newDocument(type){const settings=state.data.settings?.[0]||{},docs=state.data.docSettings?.[0]||{},validity=type==='quote'?Number(docs.quote_validity_days)||30:30,templateId=['invoice','deposit_invoice','credit_note'].includes(type)?docs.default_invoice_template_id:docs.default_quote_template_id;state.draft={id:null,document_type:type,status:'draft',issue_date:new Date().toISOString().slice(0,10),due_date:new Date(Date.now()+validity*86400000).toISOString().slice(0,10),client_id:'',client_reference:'',subject:'',sale_type:'goods_and_services',opportunity_id:'',assigned_user_id:global.PilozRuntime?.session?.user_id||null,template_id:templateId||null,deposit_rate:0,currency:settings.currency||'EUR',language:docs.document_language||settings.language||'fr',payment_terms:docs.default_payment_terms||'30 jours',payment_method:docs.default_payment_method||'Virement bancaire',internal_notes:'',public_notes:'',discount_rate:0,lines:[newLine()]};go('document-editor');}
 function editDocument(id){const doc=(state.data.documents||[]).find(x=>x.id===id);if(!doc)return;state.draft={...structuredClone(doc),lines:structuredClone((state.data.lines||[]).filter(x=>x.document_id===id))};go('document-editor');}
 function newLine(type='item'){return{id:uuid(),line_type:type,position:1,item_id:'',reference:'',name:'',description:'',quantity:type==='item'?1:0,unit:'unité',unit_cost_snapshot:0,unit_price:0,discount_rate:0,tax_rate:20,optional:false};}
 function renderDocumentEditor(){const d=state.draft;if(!d){go('sales/quotes');return;}const locked=d.status==='validated',tot=calc().document(d.lines,d.discount_rate),clientOptions=(state.data.clients||[]).map(x=>`<option value="${x.id}" ${d.client_id===x.id?'selected':''}>${e(x.legal_name||[x.first_name,x.last_name].join(' '))}</option>`).join('');document.getElementById('main').innerHTML=`<div class="erp-editor"><header class="erp-editor-bar"><div>${button('← Retour',`PilozApp.go('${d.document_type==='invoice'?'sales/invoices':'sales/quotes'}')`)}<h1>${e(labels[d.document_type]||'Document')} ${e(d.number||'— brouillon')}</h1></div><div class="actions">${button(state.panelOpen?'Masquer les paramètres':'Afficher les paramètres','PilozApp.togglePanel()')}${button('Aperçu / PDF','PilozApp.previewDocument()')}${!locked?button('Enregistrer','PilozApp.saveDocument()','btn-p','data-save-document'):''}${d.document_type==='invoice'&&d.id&&d.status==='draft'?button('Valider','PilozApp.validateInvoice()','btn-p'):''}${renderDocActions(d)}</div></header><div class="erp-editor-layout ${state.panelOpen?'':'panel-closed'}"><main class="erp-document-canvas"><section class="erp-paper"><div class="erp-document-head"><div><span class="erp-eyebrow">${e(labels[d.document_type]||d.document_type)}</span><input ${locked?'disabled':''} aria-label="Objet du document" placeholder="Objet du document" value="${e(d.subject||'')}" onchange="PilozApp.setDraft('subject',this.value)"></div><div class="erp-doc-number">${e(d.number||'Numéro attribué à la validation')}</div></div><div class="erp-client-box"><label>Client</label><select ${locked?'disabled':''} onchange="PilozApp.setDraft('client_id',this.value)"><option value="">Sélectionner un client</option>${clientOptions}</select><button class="btn btn-ghost" ${locked?'disabled':''} onclick="PilozApp.openPartnerForm('clients',true)">Créer un client</button></div>${renderLines(d,locked)}<div class="erp-totals"><div><span class="erp-cost">Coût d’achat</span><b class="erp-cost">${money(tot.totalCost)}</b><span class="erp-margin">Marge brute</span><b class="erp-margin">${money(tot.margin)}</b><small class="erp-margin">Taux de marge ${tot.marginRate===null?'—':tot.marginRate+' %'} · Taux de marque ${tot.markupRate===null?'—':tot.markupRate+' %'}</small></div><dl><dt>Total HT</dt><dd>${money(tot.ht)}</dd><dt>TVA</dt><dd>${money(tot.tax)}</dd><dt>Total TTC</dt><dd>${money(tot.ttc)}</dd></dl></div><label class="erp-notes">Notes visibles<textarea ${locked?'disabled':''} onchange="PilozApp.setDraft('public_notes',this.value)">${e(d.public_notes||'')}</textarea></label></section></main>${state.panelOpen?renderDocumentPanel(d,locked):''}</div></div>`;}
 function renderDocActions(d){if(!d.id)return'';return`<details class="erp-action-menu"><summary class="btn btn-o">Actions</summary><div>${button('Envoyer par e-mail','PilozApp.openSendDocument()','btn-ghost')}${d.document_type==='quote'?`${button('Marquer envoyé',"PilozApp.setDocumentStatus('sent')",'btn-ghost')}${button('Accepter',"PilozApp.setDocumentStatus('accepted')",'btn-ghost')}${button('Refuser',"PilozApp.setDocumentStatus('rejected')",'btn-ghost')}${button('Nouvelle version','PilozApp.newDocumentVersion()','btn-ghost')}${button('Convertir en commande',"PilozApp.convertDocument('sales_order')",'btn-ghost')}${button('Créer une facture d’acompte',"PilozApp.convertDocument('deposit_invoice')",'btn-ghost')}${button('Convertir en facture',"PilozApp.convertDocument('invoice')",'btn-ghost')}${button('Créer un contrat',"PilozApp.convertDocument('contract')",'btn-ghost')}`:''}${d.document_type==='sales_order'&&d.status==='draft'?button('Confirmer et réserver','PilozApp.openOrderConfirmation()','btn-ghost'):''}${d.document_type==='sales_order'&&['confirmed','partially_delivered'].includes(d.status)?button('Créer une livraison','PilozApp.openDeliveryForm()','btn-ghost')+button('Annuler et libérer','PilozApp.cancelOrder()','btn-ghost'):''}${d.document_type==='invoice'&&d.validated_at?button('Enregistrer un paiement','PilozApp.openPaymentForm()','btn-ghost')+button('Créer un avoir','PilozApp.convertDocument(\'credit_note\')','btn-ghost')+button('Créer une relance','PilozApp.createReminder()','btn-ghost')+button('Exporter en comptabilité','PilozApp.exportAccounting()','btn-ghost'):''}${button('Dupliquer','PilozApp.duplicateDocument()','btn-ghost')}${button('Archiver','PilozApp.setDocumentStatus(\'archived\')','btn-ghost')}</div></details>`;}
 function enhanceClientSearch(){const box=document.querySelector('.erp-client-box');if(!box||box.querySelector('[data-client-search]'))return;const search=document.createElement('label');search.dataset.clientSearch='';search.innerHTML='<span>Rechercher</span><input type="search" placeholder="Nom, e-mail, téléphone, SIRET ou ville" oninput="PilozApp.filterClientOptions(this.value)">';box.insertBefore(search,box.firstChild);}
 function filterClientOptions(value){const query=String(value||'').trim().toLocaleLowerCase('fr'),select=document.querySelector('.erp-client-box select');if(!select)return;[...select.options].forEach(option=>{if(!option.value){option.hidden=false;return;}const client=(state.data.clients||[]).find(x=>x.id===option.value),haystack=[client?.legal_name,client?.first_name,client?.last_name,client?.email,client?.phone_e164,client?.siret,client?.city].filter(Boolean).join(' ').toLocaleLowerCase('fr');option.hidden=!!query&&!haystack.includes(query);});if(query){const match=[...select.options].find(option=>option.value&&!option.hidden);if(match)select.focus();}}
 function enhanceDocumentMetadata(){enhanceClientSearch();const addBox=document.querySelector('.erp-add-line');if(addBox&&!addBox.querySelector('[data-quick-item]')){const quick=document.createElement('button');quick.type='button';quick.className='btn btn-ghost';quick.dataset.quickItem='';quick.textContent='+ Créer un article ou service';quick.onclick=quickCreateItem;addBox.appendChild(quick);}const panel=document.querySelector('.erp-editor-layout>.erp-side-panel'),d=state.draft;if(!panel||!d||panel.querySelector('[data-document-metadata]'))return;const templates=(state.data.templates||[]).filter(x=>x.status==='active'&&x.document_type===d.document_type).map(x=>`<option value="${x.id}" ${d.template_id===x.id?'selected':''}>${e(x.name)}</option>`).join(''),opportunities=(state.data.opportunities||[]).map(x=>`<option value="${x.id}" ${d.opportunity_id===x.id?'selected':''}>${e(x.name)}</option>`).join(''),box=document.createElement('div');box.dataset.documentMetadata='';box.className='erp-document-metadata';box.innerHTML=`<label>Référence client<input value="${e(d.client_reference||'')}" onchange="PilozApp.setDraft('client_reference',this.value)"></label><label>Type de vente<select onchange="PilozApp.setDraft('sale_type',this.value)"><option value="goods_and_services">Articles et services</option><option value="services" ${d.sale_type==='services'?'selected':''}>Services</option><option value="goods" ${d.sale_type==='goods'?'selected':''}>Articles</option><option value="subscription" ${d.sale_type==='subscription'?'selected':''}>Abonnement</option></select></label><label>Opportunité<select onchange="PilozApp.setDraft('opportunity_id',this.value)"><option value="">Aucune</option>${opportunities}</select></label><label>Commercial responsable<input value="${e(d.assigned_user_id||'')}" onchange="PilozApp.setDraft('assigned_user_id',this.value)"></label><label>Modèle de document<select onchange="PilozApp.setDraft('template_id',this.value)"><option value="">Modèle standard</option>${templates}</select></label>${d.document_type==='quote'?`<label>Acompte demandé (%)<input type="number" min="0" max="100" step="0.01" value="${Number(d.deposit_rate)||0}" onchange="PilozApp.setDraft('deposit_rate',this.value,true)"></label>`:''}`;panel.appendChild(box);}
 function enforceDocumentLock(){if(!state.draft?.validated_at)return;document.querySelectorAll('.erp-paper input,.erp-paper select,.erp-paper textarea,.erp-add-line button,.erp-side-panel input,.erp-side-panel select,.erp-side-panel textarea').forEach(node=>node.disabled=true);document.querySelector('[data-save-document]')?.remove();document.querySelector('.erp-add-line')?.remove();}
 function enhanceDocumentActions(){enhanceDocumentMetadata();enforceDocumentLock();const d=state.draft,actions=document.querySelector('.erp-editor-bar>.actions');if(!d?.id||!actions||d.status!=='draft'||!['deposit_invoice','credit_note'].includes(d.document_type))return;const node=document.createElement('button');node.className='btn btn-p';node.textContent='Valider';node.onclick=validateInvoice;actions.appendChild(node);}
 function renderLines(d,locked){return`<div class="erp-lines"><div class="erp-line erp-line-head"><span>Désignation</span><span>Qté</span><span class="erp-cost">Coût HT</span><span>Vente HT</span><span>Remise</span><span>TVA</span><span>Total</span><span></span></div>${d.lines.map((line,index)=>renderLine(line,index,locked)).join('')}</div>${!locked?`<div class="erp-add-line">${[['item','Article'],['free_item','Article libre'],['variant','Variante / option'],['discount','Remise'],['text','Texte'],['title','Titre'],['subtitle','Sous-titre'],['section','Section'],['subtotal','Sous-total'],['page_break','Saut de page'],['comment','Commentaire']].map(([type,label])=>button('+ '+label,`PilozApp.addLine('${type}')`,'btn-ghost')).join('')}</div>`:''}`;}
 function sectionSubtotal(index){let start=0;for(let i=index-1;i>=0;i--){if(state.draft.lines[i].line_type==='section'){start=i+1;break;}}return calc().round(state.draft.lines.slice(start,index).filter(line=>['item','free_item'].includes(line.line_type)&&!line.optional).reduce((sum,line)=>sum+calc().line(line).ht,0));}
 function renderLine(line,index,locked){const drag=!locked?`draggable="true" ondragstart="PilozApp.dragLine(${index})" ondragover="event.preventDefault()" ondrop="PilozApp.dropLine(${index})"`:'',special=!['item','free_item'].includes(line.line_type),amount=calc().line(line).ht,itemOptions=(state.data.catalog||[]).map(item=>`<option value="${item.id}" ${line.item_id===item.id?'selected':''}>${e(item.reference)} — ${e(item.name)}</option>`).join('');if(special)return`<div class="erp-line erp-line-special" ${drag}><input ${locked?'disabled':''} value="${e(line.name||line.description||'')}" placeholder="${e(line.line_type)}" onchange="PilozApp.setLine(${index},'name',this.value)"><span>${e(line.line_type.replaceAll('_',' '))}${line.line_type==='subtotal'?` · ${money(sectionSubtotal(index))}`:''}</span>${!locked?`<button class="ic" onclick="PilozApp.moveLine(${index},-1)">↑</button><button class="ic" onclick="PilozApp.moveLine(${index},1)">↓</button><button class="ic" onclick="PilozApp.removeLine(${index})">×</button>`:''}</div>`;return`<div class="erp-line ${line.optional?'erp-line-optional':''}" ${drag}><div><select ${locked?'disabled':''} onchange="PilozApp.selectItem(${index},this.value)"><option value="">Article libre</option>${itemOptions}</select><input ${locked?'disabled':''} value="${e(line.name||'')}" placeholder="Désignation" onchange="PilozApp.setLine(${index},'name',this.value)"><textarea ${locked?'disabled':''} placeholder="Description" onchange="PilozApp.setLine(${index},'description',this.value)">${e(line.description||'')}</textarea></div><input ${locked?'disabled':''} type="number" step="0.01" value="${line.quantity}" onchange="PilozApp.setLine(${index},'quantity',this.value,true)"><input class="erp-cost" ${locked?'disabled':''} type="number" step="0.01" value="${line.unit_cost_snapshot}" onchange="PilozApp.setLine(${index},'unit_cost_snapshot',this.value,true)"><input ${locked?'disabled':''} type="number" step="0.01" value="${line.unit_price}" onchange="PilozApp.setLine(${index},'unit_price',this.value,true)"><input ${locked?'disabled':''} type="number" step="0.01" value="${line.discount_rate}" onchange="PilozApp.setLine(${index},'discount_rate',this.value,true)"><input ${locked?'disabled':''} type="number" step="0.01" value="${line.tax_rate}" onchange="PilozApp.setLine(${index},'tax_rate',this.value,true)"><b>${money(amount)}</b><div>${!locked?`<button class="ic" title="${line.optional?'Rendre obligatoire':'Marquer comme option'}" onclick="PilozApp.setLine(${index},'optional',${!line.optional})">◇</button><button class="ic" onclick="PilozApp.duplicateLine(${index})">⧉</button><button class="ic" onclick="PilozApp.removeLine(${index})">×</button>`:''}</div></div>`;}
 function renderDocumentPanel(d,locked){return`<aside class="erp-side-panel"><h2>Paramètres</h2><label>Date d’émission<input ${locked?'disabled':''} type="date" value="${e(d.issue_date)}" onchange="PilozApp.setDraft('issue_date',this.value)"></label><label>Date de validité / échéance<input ${locked?'disabled':''} type="date" value="${e(d.due_date||'')}" onchange="PilozApp.setDraft('due_date',this.value)"></label><label>Langue<select ${locked?'disabled':''} onchange="PilozApp.setDraft('language',this.value)"><option value="fr">Français</option><option value="en" ${d.language==='en'?'selected':''}>Anglais</option></select></label><label>Devise<input ${locked?'disabled':''} value="${e(d.currency||'EUR')}" maxlength="3" onchange="PilozApp.setDraft('currency',this.value.toUpperCase())"></label><label>Conditions de paiement<input ${locked?'disabled':''} value="${e(d.payment_terms||'')}" onchange="PilozApp.setDraft('payment_terms',this.value)"></label><label>Mode de paiement<input ${locked?'disabled':''} value="${e(d.payment_method||'')}" onchange="PilozApp.setDraft('payment_method',this.value)"></label><label>Remise globale (%)<input ${locked?'disabled':''} type="number" min="0" max="100" value="${d.discount_rate||0}" onchange="PilozApp.setDraft('discount_rate',this.value,true)"></label><label>Notes internes<textarea ${locked?'disabled':''} onchange="PilozApp.setDraft('internal_notes',this.value)">${e(d.internal_notes||'')}</textarea></label></aside>`;}
 function rerenderDocument(){renderDocumentEditor();setTimeout(enhanceDocumentActions,0);}
 function setDraft(field,value,numeric=false){state.draft[field]=numeric?Number(value)||0:value;if(field==='client_id'){const client=(state.data.clients||[]).find(x=>x.id===value);if(client){state.draft.language=client.language||state.draft.language;state.draft.payment_terms=client.payment_terms||state.draft.payment_terms;state.draft.payment_method=client.preferred_payment_method||state.draft.payment_method;state.draft.discount_rate=Number(client.discount_rate)||state.draft.discount_rate;}}rerenderDocument();}
 function setLine(index,field,value,numeric=false){state.draft.lines[index][field]=numeric?Number(value)||0:value;rerenderDocument();}
 function addLine(type){let line;if(type==='variant'){line=newLine('item');line.optional=true;line.name='Option';}else if(type==='discount'){line=newLine('free_item');line.name='Remise';line.quantity=1;}else{line=newLine(type);}line.position=state.draft.lines.length+1;state.draft.lines.push(line);rerenderDocument();}
 function removeLine(index){state.draft.lines.splice(index,1);state.draft.lines.forEach((x,i)=>x.position=i+1);rerenderDocument();}
 function duplicateLine(index){const copy={...structuredClone(state.draft.lines[index]),id:uuid(),position:index+2};state.draft.lines.splice(index+1,0,copy);state.draft.lines.forEach((x,i)=>x.position=i+1);rerenderDocument();}
 function moveLine(index,delta){const next=index+delta;if(next<0||next>=state.draft.lines.length)return;[state.draft.lines[index],state.draft.lines[next]]=[state.draft.lines[next],state.draft.lines[index]];state.draft.lines.forEach((x,i)=>x.position=i+1);rerenderDocument();}
 function dragLine(index){state.dragLine=index;}
 function dropLine(index){if(state.dragLine==null||state.dragLine===index)return;const [line]=state.draft.lines.splice(state.dragLine,1);state.draft.lines.splice(index,0,line);state.dragLine=null;state.draft.lines.forEach((x,i)=>x.position=i+1);rerenderDocument();}
 function selectItem(index,id){const item=(state.data.catalog||[]).find(x=>x.id===id),line=state.draft.lines[index];if(!item){line.item_id='';rerenderDocument();return;}Object.assign(line,{item_id:item.id,reference:item.reference,name:item.name,description:item.sales_description||item.short_description||'',unit:item.unit,unit_cost_snapshot:item.cost_price||item.purchase_price||0,unit_price:item.sale_price||0,tax_rate:item.tax_rate||0});rerenderDocument();}
 function togglePanel(){state.panelOpen=!state.panelOpen;rerenderDocument();}
 async function saveDocument(){if(state.busy)return;const d=state.draft;if(d.validated_at){notice('Ce document validé est verrouillé.','error');return;}if(!d.client_id&&['quote','invoice','deposit_invoice','credit_note','sales_order','contract'].includes(d.document_type)){notice('Sélectionnez un client.','error');return;}state.busy=true;try{const totals=calc().document(d.lines,d.discount_rate),payload={company_id:state.companyId,document_type:d.document_type,version:Number(d.version)||1,client_id:d.client_id||null,client_reference:d.client_reference||null,status:d.status||'draft',issue_date:d.issue_date,due_date:d.due_date||null,subject:d.subject||null,sale_type:d.sale_type||null,opportunity_id:d.opportunity_id||null,assigned_user_id:d.assigned_user_id||null,template_id:d.template_id||null,deposit_rate:Number(d.deposit_rate)||0,currency:d.currency||'EUR',language:d.language||'fr',payment_terms:d.payment_terms||null,payment_method:d.payment_method||null,internal_notes:d.internal_notes||null,public_notes:d.public_notes||null,discount_rate:d.discount_rate||0,source_document_id:d.source_document_id||null,total_cost:totals.totalCost,total_excl_tax:totals.ht,total_tax:totals.tax,total_incl_tax:totals.ttc};let id=d.id;if(id){await api().update('documents',id,payload);await api().request(`/rest/v1/document_lines?document_id=eq.${encodeURIComponent(id)}`,{method:'DELETE',headers:{Prefer:'return=minimal'}});}else{id=(await api().insert('documents',payload))[0].id;d.id=id;}const rows=d.lines.map((line,index)=>{const amounts=calc().line(line);return{company_id:state.companyId,document_id:id,position:index+1,line_type:line.line_type||'item',item_id:line.item_id||null,reference:line.reference||null,name:line.name||null,description:line.description||null,quantity:Number(line.quantity)||0,unit:line.unit||null,unit_cost_snapshot:Number(line.unit_cost_snapshot)||0,unit_price:Number(line.unit_price)||0,discount_rate:Number(line.discount_rate)||0,tax_rate:Number(line.tax_rate)||0,optional:!!line.optional,total_excl_tax:amounts.ht,total_tax:amounts.tax,total_incl_tax:amounts.ttc};});if(rows.length)await api().insert('document_lines',rows);await refresh();editDocument(id);notice('Document enregistré.','success');}catch(error){notice(error.message,'error');}finally{state.busy=false;}}
 async function validateInvoice(){if(!state.draft?.id||state.busy)return;state.busy=true;try{await api().rpc('validate_invoice',{target_document_id:state.draft.id});await refresh();editDocument(state.draft.id);notice('Facture validée et verrouillée.','success');}catch(error){notice(error.message,'error');}finally{state.busy=false;}}
 async function setDocumentStatus(statusValue){if(state.busy)return;state.busy=true;try{const changes={status:statusValue,archived_at:statusValue==='archived'?new Date().toISOString():null};if(!state.draft.number&&state.draft.document_type==='quote'&&statusValue!=='draft')changes.number=await api().rpc('next_document_number',{target_company_id:state.companyId,target_type:'quote'});await api().update('documents',state.draft.id,changes);await refresh();editDocument(state.draft.id);notice('Statut mis à jour.','success');}catch(error){notice(error.message,'error');}finally{state.busy=false;}}
 async function duplicateDocument(){const source=state.draft,copy=structuredClone(source);Object.assign(copy,{id:null,number:null,status:'draft',validated_at:null,version:1,source_document_id:source.id,issue_date:new Date().toISOString().slice(0,10)});copy.lines=copy.lines.map(line=>({...line,id:uuid()}));state.draft=copy;rerenderDocument();notice('Copie créée. Enregistrez le nouveau brouillon.');}
 async function newDocumentVersion(){const source=state.draft,copy=structuredClone(source);Object.assign(copy,{id:null,number:null,status:'draft',validated_at:null,version:Number(source.version||1)+1,source_document_id:source.id,issue_date:new Date().toISOString().slice(0,10)});copy.lines=copy.lines.map(line=>({...line,id:uuid()}));state.draft=copy;rerenderDocument();notice(`Version ${copy.version} préparée. Enregistrez-la.`);}
 async function convertDocument(type){const source=structuredClone(state.draft);Object.assign(source,{id:null,number:null,document_type:type,status:'draft',validated_at:null,source_document_id:state.draft.id,issue_date:new Date().toISOString().slice(0,10),template_id:['invoice','deposit_invoice','credit_note'].includes(type)?state.data.docSettings?.[0]?.default_invoice_template_id:state.data.docSettings?.[0]?.default_quote_template_id});source.lines=source.lines.map(line=>({...line,id:uuid()}));state.draft=source;rerenderDocument();notice(`Conversion préparée en ${labels[type]||type}. Enregistrez le brouillon.`);}
 function openOrderConfirmation(){const options=(state.data.warehouses||[]).map(x=>`<option value="${x.id}">${e(x.name)}</option>`).join('');modal('Confirmer la commande',`<form id="order-confirm-form"><label class="phase1-field"><span>Entrepôt de réservation</span><select name="warehouse_id">${options}</select></label></form>`,button('Annuler','PilozApp.closeModal()')+button('Confirmer et réserver','PilozApp.confirmOrder()','btn-p'));}
 async function confirmOrder(){if(state.busy)return;const warehouseId=new FormData(document.getElementById('order-confirm-form')).get('warehouse_id');state.busy=true;try{await api().rpc('confirm_sales_order',{target_document_id:state.draft.id,target_warehouse_id:warehouseId});closeModal();await refresh();editDocument(state.draft.id);notice('Commande confirmée et stock réservé.','success');}catch(error){notice(error.message,'error');}finally{state.busy=false;}}
 async function cancelOrder(){try{await api().rpc('cancel_sales_order',{target_document_id:state.draft.id});await refresh();editDocument(state.draft.id);notice('Commande annulée et réservations libérées.','success');}catch(error){notice(error.message,'error');}}
 function openDeliveryForm(){const validatedDeliveryIds=new Set((state.data.deliveries||[]).filter(x=>x.sales_order_id===state.draft.id&&x.status==='validated').map(x=>x.id)),lines=state.draft.lines.filter(line=>line.item_id&&(state.data.catalog||[]).find(item=>item.id===line.item_id)?.stock_managed).map(line=>{const delivered=(state.data.deliveryLines||[]).filter(x=>x.order_line_id===line.id&&validatedDeliveryIds.has(x.delivery_id)).reduce((sum,x)=>sum+Number(x.quantity),0);return{...line,remaining:Math.max(0,Number(line.quantity)-delivered)};}).filter(line=>line.remaining>0),warehouses=(state.data.warehouses||[]).map(x=>`<option value="${x.id}">${e(x.name)}</option>`).join('');if(!lines.length){notice('Tous les articles stockés de cette commande ont déjà été livrés.');return;}modal('Créer une livraison',`<form id="delivery-form" onsubmit="return false"><label class="phase1-field"><span>Entrepôt</span><select name="warehouse_id">${warehouses}</select></label><div class="phase1-table-wrap"><table class="phase1-table"><tr><th>Article</th><th>Commandé</th><th>Restant</th><th>À livrer</th></tr>${lines.map(line=>`<tr><td>${e(line.name)}</td><td>${line.quantity}</td><td>${line.remaining}</td><td><input name="line_${line.id}" type="number" min="0" max="${line.remaining}" step="0.01" value="${line.remaining}"></td></tr>`).join('')}</table></div></form>`,button('Annuler','PilozApp.closeModal()')+button('Créer et valider','PilozApp.saveDelivery()','btn-p'));}
 async function saveDelivery(){if(state.busy)return;const form=document.getElementById('delivery-form'),fd=new FormData(form),warehouseId=fd.get('warehouse_id');state.busy=true;try{const number=await api().rpc('next_document_number',{target_company_id:state.companyId,target_type:'delivery_note'}),delivery=(await api().insert('deliveries',{company_id:state.companyId,number,sales_order_id:state.draft.id,client_id:state.draft.client_id,warehouse_id:warehouseId}))[0],rows=state.draft.lines.filter(x=>x.item_id&&Number(fd.get('line_'+x.id))>0).map(x=>({company_id:state.companyId,delivery_id:delivery.id,order_line_id:x.id,item_id:x.item_id,quantity:Number(fd.get('line_'+x.id))}));if(!rows.length)throw new Error('Aucune quantité à livrer.');await api().insert('delivery_lines',rows);await api().rpc('validate_delivery',{target_delivery_id:delivery.id});closeModal();await refresh();editDocument(state.draft.id);notice('Livraison validée et stock décrémenté une seule fois.','success');}catch(error){notice(error.message,'error');}finally{state.busy=false;}}
 function openPaymentForm(){const paid=(state.data.payments||[]).filter(x=>x.document_id===state.draft.id&&x.status==='confirmed').reduce((s,x)=>s+Number(x.amount),0),remaining=Math.max(0,Number(state.draft.total_incl_tax)-paid);modal('Enregistrer un paiement',`<form id="payment-form" class="phase1-grid" onsubmit="return false">${field('Montant','amount',remaining,'number','min="0.01" step="0.01"')}${field('Date','paid_at',new Date().toISOString().slice(0,10),'date')}${field('Mode de paiement','payment_method',state.draft.payment_method)}${field('Référence','reference','')}</form>`,button('Annuler','PilozApp.closeModal()')+button('Enregistrer','PilozApp.savePayment()','btn-p'));}
 async function savePayment(){const data=Object.fromEntries(new FormData(document.getElementById('payment-form'))),amount=Number(data.amount);if(amount<=0){notice('Montant invalide.','error');return;}data.company_id=state.companyId;data.document_id=state.draft.id;data.amount=amount;data.paid_at=new Date(data.paid_at+'T12:00:00').toISOString();try{await api().insert('payments',data);const total=(state.data.payments||[]).filter(x=>x.document_id===state.draft.id&&x.status==='confirmed').reduce((s,x)=>s+Number(x.amount),0)+amount;await api().update('documents',state.draft.id,{status:total>=Number(state.draft.total_incl_tax)?'paid':'partially_paid'});closeModal();await refresh();editDocument(state.draft.id);notice('Paiement enregistré.','success');}catch(error){notice(error.message,'error');}}
 function createReminder(){const source=structuredClone(state.draft);Object.assign(source,{id:null,number:null,document_type:'reminder',status:'draft',validated_at:null,source_document_id:state.draft.id,subject:`Relance — ${state.draft.number||state.draft.subject||'facture'}`,issue_date:new Date().toISOString().slice(0,10)});source.lines=source.lines.map(line=>({...line,id:uuid()}));state.draft=source;rerenderDocument();notice('Relance préparée. Enregistrez puis envoyez-la.');}
