 async function previewDocument(){const d=state.draft,tot=calc().document(d.lines,d.discount_rate),client=(state.data.clients||[]).find(x=>x.id===d.client_id),win=open('','_blank','width=900,height=1000');if(!win)return;win.document.write('<p style="font:16px Arial;padding:30px">Préparation du document…</p>');try{let html='<header><div>{{company.logo}}</div><h1>{{company.name}}</h1></header><section><h2>{{document.number}}</h2><p>{{client.name}}<br>{{client.address}}</p>{{document.lines}}<div class="totals"><p>Total HT : <b>{{document.total_ht}}</b></p><p>TVA : <b>{{document.total_vat}}</b></p><p>Total TTC : <b>{{document.total_ttc}}</b></p></div><p>{{document.payment_terms}}</p></section>',css='body{font:14px Arial;margin:45px;color:#172038}.company-logo{max-width:180px;max-height:90px}.document-lines{width:100%;border-collapse:collapse;margin:25px 0}.document-lines th,.document-lines td{padding:9px;border-bottom:1px solid #ddd;text-align:left}.totals{margin-left:auto;width:300px;text-align:right}.page-break{break-after:page}';if(d.template_id){const versions=await api().query('document_template_versions',`select=*&template_id=eq.${encodeURIComponent(d.template_id)}&order=version.desc&limit=1`),version=versions[0];if(version){const safe=sanitizeTemplate(version.html,version.css);html=safe.html;css=safe.css;}}const rendered=applyDocumentVariables(html,d,client,tot);win.document.open();win.document.write(`<!doctype html><html lang="${e(d.language||'fr')}"><meta charset="utf-8"><title>${e(d.number||labels[d.document_type])}</title><style>${css}@media print{.print-action{display:none}}</style><button class="print-action" onclick="print()">Imprimer / Enregistrer en PDF</button>${rendered}</html>`);win.document.close();}catch(error){win.document.open();win.document.write(`<p style="font:16px Arial;padding:30px;color:#b42318">${e(error.message)}</p>`);win.document.close();}}

