 function stockAlerts(){const levels=state.data.levels||[],items=state.data.catalog||[],supplierItems=state.data.supplierItems||[],alerts=items.filter(x=>x.stock_managed).flatMap(item=>{const itemLevels=levels.filter(l=>l.item_id===item.id),physical=itemLevels.reduce((s,l)=>s+Number(l.physical_quantity||0),0),reserved=itemLevels.reduce((s,l)=>s+Number(l.reserved_quantity||0),0),expected=itemLevels.reduce((s,l)=>s+Number(l.expected_quantity||0),0),available=physical-reserved,result=[];if(available<0)result.push({item,message:`Réservation impossible : déficit de ${Math.abs(available)}`,kind:'danger'});else if(available===0)result.push({item,message:expected>0?`Rupture — ${expected} attendu après réception`:'Rupture ou stock entièrement réservé',kind:'danger'});else if(available<=Number(item.reorder_point??item.minimum_stock??0))result.push({item,message:`Stock disponible ${available} — réapprovisionnement conseillé`,kind:'warn'});if(item.maximum_stock!=null&&physical>Number(item.maximum_stock))result.push({item,message:`Surstock : ${physical} pour un maximum de ${item.maximum_stock}`,kind:'info'});if(!supplierItems.some(link=>link.catalog_item_id===item.id))result.push({item,message:'Article sans fournisseur',kind:'warn'});if(!item.cost_price)result.push({item,message:'Coût de revient non renseigné',kind:'info'});return result;}),fallback={id:'operations',name:'Opérations stock',reference:''};for(const order of state.data.purchaseOrders||[]){if(order.expected_date&&new Date(order.expected_date)<new Date()&&!['received','cancelled'].includes(order.status))alerts.push({item:fallback,message:`Réception en retard pour ${order.number||'une commande fournisseur'}`,kind:'warn'});}for(const inventory of state.data.inventories||[]){if(['draft','counted'].includes(inventory.status))alerts.push({item:fallback,message:`Inventaire en attente : ${inventory.name}`,kind:'info'});}return alerts;}
 function renderStock(){const levels=state.data.levels||[],items=(state.data.catalog||[]).filter(x=>x.stock_managed);document.getElementById('main').innerHTML=top('Stock — Vue d’ensemble',button('Nouveau mouvement','PilozApp.openMovementForm()','btn-p'))+`<div class="erp-kpis"><article><span>Articles stockés</span><b>${items.length}</b></article><article><span>Entrepôts</span><b>${(state.data.warehouses||[]).length}</b></article><article><span>Réservations actives</span><b>${(state.data.reservations||[]).filter(x=>x.status==='active').length}</b></article><article><span>Alertes</span><b>${stockAlerts().length}</b></article></div><div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>Article</th><th>Entrepôt</th><th>Physique</th><th>Réservé</th><th>Disponible</th><th>Attendu</th><th>Transit</th><th>Endommagé</th></tr>${levels.map(level=>{const item=items.find(x=>x.id===level.item_id),wh=(state.data.warehouses||[]).find(x=>x.id===level.warehouse_id),available=Number(level.available_quantity??(Number(level.physical_quantity)-Number(level.reserved_quantity)));return`<tr><td><b>${e(item?.name||'—')}</b><small>${e(item?.reference||'')}</small></td><td>${e(wh?.name||'—')}</td><td>${level.physical_quantity}</td><td>${level.reserved_quantity}</td><td><b>${available}</b></td><td>${level.expected_quantity||0}</td><td>${level.in_transit_quantity||0}</td><td>${level.damaged_quantity||0}</td></tr>`;}).join('')}</table></div>`;}
