 function renderPurchaseOrders(){const rows=state.data.purchaseOrders||[];document.getElementById('main').innerHTML=top('Commandes fournisseurs',button('Nouvelle commande','PilozApp.openPurchaseOrderForm()','btn-p'))+(rows.length?`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>Numéro</th><th>Fournisseur</th><th>Date</th><th>Prévue</th><th>HT</th><th>TTC</th><th>Statut</th><th></th></tr>${rows.map(x=>`<tr><td class="phase1-mono"><b>${e(x.number||'Brouillon')}</b></td><td>${e(x.supplier?.legal_name||'—')}</td><td>${date(x.order_date)}</td><td>${date(x.expected_date)}</td><td>${money(x.total_excl_tax)}</td><td>${money(x.total_incl_tax)}</td><td>${status(x.status)}</td><td>${x.status==='draft'?button('Confirmer',`PilozApp.confirmPurchaseOrder('${x.id}')`,'btn-p'):''}</td></tr>`).join('')}</table></div>`:empty('Aucune commande fournisseur','Préparez vos approvisionnements depuis les fournisseurs et alertes de stock.'));}
 function openPurchaseOrderForm(){const suppliers=(state.data.suppliers||[]).map(x=>`<option value="${x.id}">${e(x.legal_name)}</option>`).join(''),warehouses=(state.data.warehouses||[]).map(x=>`<option value="${x.id}">${e(x.name)}</option>`).join(''),items=(state.data.catalog||[]).filter(x=>x.item_type!=='service').map(x=>`<option value="${x.id}">${e(x.reference)} — ${e(x.name)}</option>`).join('');modal('Nouvelle commande fournisseur',`<form id="po-form" class="phase1-grid" onsubmit="return false"><label class="phase1-field"><span>Fournisseur *</span><select name="supplier_id" required>${suppliers}</select></label><label class="phase1-field"><span>Entrepôt *</span><select name="warehouse_id" required>${warehouses}</select></label>${field('Date prévue','expected_date','','date')}<label class="phase1-field"><span>Article *</span><select name="item_id">${items}</select></label>${field('Quantité','quantity',1,'number','step="0.01" min="0.01"')}${field('Prix d’achat HT','unit_price',0,'number','step="0.01"')}${field('Remise (%)','discount_rate',0,'number','step="0.01"')}${field('TVA (%)','tax_rate',20,'number','step="0.01"')}</form>`,button('Annuler','PilozApp.closeModal()')+button('Enregistrer','PilozApp.savePurchaseOrder()','btn-p'));}
 async function savePurchaseOrder(){const fd=Object.fromEntries(new FormData(document.getElementById('po-form'))),qty=Number(fd.quantity),price=Number(fd.unit_price),discount=Number(fd.discount_rate),tax=Number(fd.tax_rate),ht=calc().round(qty*price*(1-discount/100)),vat=calc().round(ht*tax/100);try{const number=await api().rpc('next_document_number',{target_company_id:state.companyId,target_type:'purchase_order'}),po=(await api().insert('purchase_orders',{company_id:state.companyId,number,supplier_id:fd.supplier_id,warehouse_id:fd.warehouse_id,expected_date:fd.expected_date||null,total_excl_tax:ht,total_tax:vat,total_incl_tax:ht+vat}))[0];await api().insert('purchase_order_lines',{company_id:state.companyId,purchase_order_id:po.id,item_id:fd.item_id,quantity:qty,unit_price:price,discount_rate:discount,tax_rate:tax});closeModal();await refresh();notice('Commande fournisseur enregistrée.','success');}catch(error){notice(error.message,'error');}}
 async function confirmPurchaseOrder(id){try{await api().rpc('confirm_purchase_order',{target_order_id:id});await refresh();notice('Commande confirmée : le stock est désormais attendu.','success');}catch(error){notice(error.message,'error');}}
 function renderReceipts(){const rows=state.data.receipts||[];document.getElementById('main').innerHTML=top('Réceptions fournisseurs',button('Nouvelle réception','PilozApp.openReceiptForm()','btn-p'))+(rows.length?`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>Numéro</th><th>Commande</th><th>Entrepôt</th><th>Réception</th><th>Statut</th><th></th></tr>${rows.map(x=>`<tr><td>${e(x.number||'—')}</td><td>${e(x.purchase_order_id||'Libre')}</td><td>${e((state.data.warehouses||[]).find(w=>w.id===x.warehouse_id)?.name||'—')}</td><td>${date(x.received_at)}</td><td>${status(x.status)}</td><td>${x.status==='draft'?button('Valider',`PilozApp.validateReceipt('${x.id}')`,'btn-p'):''}</td></tr>`).join('')}</table></div>`:empty('Aucune réception','Les réceptions validées créent automatiquement les entrées de stock et mettent à jour le coût moyen.'));}
 function openReceiptForm(){const orderLines=(state.data.purchaseOrderLines||[]).filter(line=>Number(line.received_quantity)<Number(line.quantity)).map(line=>{const order=(state.data.purchaseOrders||[]).find(x=>x.id===line.purchase_order_id),item=(state.data.catalog||[]).find(x=>x.id===line.item_id),remaining=Number(line.quantity)-Number(line.received_quantity);return`<option value="${line.id}">${e(order?.number||'Commande')} — ${e(item?.reference||'')} ${e(item?.name||'')} — reste ${remaining}</option>`;}).join(''),warehouses=(state.data.warehouses||[]).map(x=>`<option value="${x.id}">${e(x.name)}</option>`).join(''),items=(state.data.catalog||[]).filter(x=>x.stock_managed).map(x=>`<option value="${x.id}">${e(x.reference)} — ${e(x.name)}</option>`).join('');modal('Nouvelle réception',`<form id="receipt-form" class="phase1-grid" onsubmit="return false"><label class="phase1-field full"><span>Ligne de commande fournisseur</span><select name="purchase_order_line_id"><option value="">Réception libre</option>${orderLines}</select></label><label class="phase1-field"><span>Entrepôt *</span><select name="warehouse_id">${warehouses}</select></label><label class="phase1-field"><span>Article pour réception libre</span><select name="item_id">${items}</select></label>${field('Quantité reçue','quantity',1,'number','min="0.01" step="0.01"')}${field('Coût unitaire réel','unit_cost',0,'number','step="0.0001"')}</form>`,button('Annuler','PilozApp.closeModal()')+button('Enregistrer le brouillon','PilozApp.saveReceipt()','btn-p'));}
 async function saveReceipt(){const fd=Object.fromEntries(new FormData(document.getElementById('receipt-form'))),orderLine=(state.data.purchaseOrderLines||[]).find(x=>x.id===fd.purchase_order_line_id),order=orderLine?(state.data.purchaseOrders||[]).find(x=>x.id===orderLine.purchase_order_id):null,quantity=Number(fd.quantity);if(orderLine&&quantity>Number(orderLine.quantity)-Number(orderLine.received_quantity)){notice('La quantité dépasse le reliquat de la commande.','error');return;}try{const number=await api().rpc('next_document_number',{target_company_id:state.companyId,target_type:'goods_receipt'}),receipt=(await api().insert('goods_receipts',{company_id:state.companyId,number,purchase_order_id:order?.id||null,warehouse_id:fd.warehouse_id||order?.warehouse_id}))[0];await api().insert('goods_receipt_lines',{company_id:state.companyId,goods_receipt_id:receipt.id,purchase_order_line_id:orderLine?.id||null,item_id:orderLine?.item_id||fd.item_id,quantity,unit_cost:Number(fd.unit_cost)});closeModal();await refresh();notice('Réception enregistrée en brouillon.','success');}catch(error){notice(error.message,'error');}}
 async function validateReceipt(id){try{await api().rpc('validate_goods_receipt',{target_receipt_id:id});await refresh();notice('Réception validée, stock et coût moyen mis à jour.','success');}catch(error){notice(error.message,'error');}}

 const purchaseViews={requests:renderSupplierRequests,orders:renderPurchaseOrders,receipts:renderReceipts,returns:renderSupplierReturns};
 function restrictPurchaseView(renderer,title){return function(){if(!allowed('view_purchase_prices')){document.getElementById('main').innerHTML=top(title)+empty('Accès restreint','Votre rôle ne permet pas de consulter les prix d’achat et les approvisionnements.');return;}renderer();};}
 renderSupplierRequests=restrictPurchaseView(purchaseViews.requests,'Demandes de prix');renderPurchaseOrders=restrictPurchaseView(purchaseViews.orders,'Commandes fournisseurs');renderReceipts=restrictPurchaseView(purchaseViews.receipts,'Réceptions fournisseurs');renderSupplierReturns=restrictPurchaseView(purchaseViews.returns,'Retours fournisseurs');

 function renderTemplates(){const rows=state.data.templates||[];document.getElementById('main').innerHTML=top('Modèles de documents',`<label class="btn btn-o">Importer<input type="file" accept="application/json" hidden onchange="PilozApp.importTemplate(this.files[0])"></label>${button('Nouveau modèle','PilozApp.newTemplate()','btn-p')}`)+(rows.length?`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>Nom</th><th>Type</th><th>Langue</th><th>Version</th><th>Par défaut</th><th>Modification</th><th>Statut</th><th></th></tr>${rows.map(x=>`<tr><td><b>${e(x.name)}</b></td><td>${e(x.document_type)}</td><td>${e(x.language)}</td><td>v${x.current_version}</td><td>${x.is_default?'Oui':'Non'}</td><td>${date(x.updated_at)}</td><td>${status(x.status)}</td><td><details class="erp-action-menu"><summary class="ic">⋮</summary><div>${button('Modifier / renommer',`PilozApp.editTemplate('${x.id}')`,'btn-ghost')}${button('Prévisualiser',`PilozApp.previewTemplate('${x.id}')`,'btn-ghost')}${button('Dupliquer',`PilozApp.duplicateTemplate('${x.id}')`,'btn-ghost')}${button('Exporter',`PilozApp.exportTemplate('${x.id}')`,'btn-ghost')}${button(x.status==='active'?'Désactiver':'Activer',`PilozApp.setTemplateStatus('${x.id}','${x.status==='active'?'inactive':'active'}')`,'btn-ghost')}${button('Archiver',`PilozApp.setTemplateStatus('${x.id}','archived')`,'btn-ghost')}</div></details></td></tr>`).join('')}</table></div>`:empty('Aucun modèle','Créez un modèle visuel ou HTML/CSS sécurisé.',button('Créer','PilozApp.newTemplate()','btn-p')));}
 function defaultTemplate(){const blocks=[['entreprise','Entreprise'],['document','Document'],['client','Client'],['articles','Articles'],['totaux','Totaux'],['paiement','Paiement']].map(([type,label])=>({id:uuid(),type,label}));return{templateId:null,name:'Nouveau modèle',document_type:'quote',language:'fr',status:'active',is_default:false,version:0,mode:'visual',visual_schema:{blocks},html:blocks.map(block=>templateBlockHtml(block.type,block.id)).join(''),css:'body{font-family:Arial,sans-serif;color:#172038} section{margin:16px 0} .document-lines{width:100%;border-collapse:collapse} .document-lines td,.document-lines th{padding:8px;border-bottom:1px solid #ddd}'};}
 function newTemplate(){state.templateDraft=defaultTemplate();go('template-editor');}
 async function editTemplate(id){const template=(state.data.templates||[]).find(x=>x.id===id);if(!template)return;try{const versions=await api().query('document_template_versions',`select=*&template_id=eq.${encodeURIComponent(id)}&order=version.desc`),current=versions[0]||{};state.templateDraft={templateId:id,name:template.name,document_type:template.document_type,language:template.language,status:template.status,is_default:template.is_default,version:template.current_version,mode:'visual',visual_schema:current.visual_schema||{blocks:[]},html:current.html||'',css:current.css||'',versions};go('template-editor');}catch(error){notice(error.message,'error');}}
 function renderTemplateEditor(){const t=state.templateDraft;if(!t){go('templates');return;}const variables=['company.name','company.logo','company.siret','company.vat_number','client.name','client.address','document.number','document.issue_date','document.due_date','document.total_ht','document.total_vat','document.total_ttc','document.lines','document.payment_terms'];document.getElementById('main').innerHTML=`<div class="erp-editor"><header class="erp-editor-bar"><div>${button('← Modèles',"PilozApp.go('templates')")}<input class="erp-title-input" value="${e(t.name)}" onchange="PilozApp.setTemplate('name',this.value)"></div><div class="erp-mode-switch"><button class="${t.mode==='visual'?'on':''}" onclick="PilozApp.setTemplateMode('visual')">Mode édition</button><button class="${t.mode==='code'?'on':''}" onclick="PilozApp.setTemplateMode('code')">Mode code</button><button class="${t.mode==='preview'?'on':''}" onclick="PilozApp.setTemplateMode('preview')">Mode aperçu</button></div><div>${button('Enregistrer une version','PilozApp.saveTemplate()','btn-p')}</div></header><div class="erp-template-layout"><aside class="erp-blocks"><h2>Insérer des données</h2>${['Entreprise','Client','Document','Commercial','Articles','Totaux','Paiement','Livraison','Contrat','Stock','Champs personnalisés'].map(x=>`<button onclick="PilozApp.addTemplateBlock('${e(x.toLowerCase())}')">+ ${e(x)}</button>`).join('')}<details><summary>Variables disponibles</summary>${variables.map(v=>`<button class="phase1-mono" onclick="PilozApp.insertVariable('${v}')">{{${e(v)}}}</button>`).join('')}</details></aside><main class="erp-template-workspace">${renderTemplateMode(t)}</main><aside class="erp-side-panel"><h2>Paramètres</h2><label>Type<select onchange="PilozApp.setTemplate('document_type',this.value)">${['quote','invoice','deposit_invoice','credit_note','sales_order','delivery_note','purchase_order','contract','reminder','statement'].map(x=>`<option value="${x}" ${t.document_type===x?'selected':''}>${e(x)}</option>`).join('')}</select></label><label>Langue<select onchange="PilozApp.setTemplate('language',this.value)"><option value="fr">Français</option><option value="en" ${t.language==='en'?'selected':''}>Anglais</option></select></label><label class="phase1-check"><input type="checkbox" ${t.is_default?'checked':''} onchange="PilozApp.setTemplate('is_default',this.checked)"><span>Modèle par défaut</span></label><h2>Historique</h2>${(t.versions||[]).map(v=>`<button class="erp-version" onclick="PilozApp.restoreTemplateVersion('${v.id}')"><b>Version ${v.version}</b><small>${date(v.created_at)} · ${e(v.change_comment||'Sans commentaire')}</small></button>`).join('')||'<p>Aucune version publiée.</p>'}</aside></div></div>`;}
 function lineNumbers(value){return String(value||'').split('\n').map((_,index)=>index+1).join('\n');}
 function renderTemplateMode(t){if(t.mode==='code')return`<div class="erp-code-shell"><div class="erp-code-toolbar"><input id="template-code-search" placeholder="Rechercher"><button onclick="PilozApp.findTemplateCode()">Rechercher</button><button onclick="document.execCommand('undo')">Annuler</button><button onclick="document.execCommand('redo')">Rétablir</button><button onclick="PilozApp.toggleTemplateFullscreen()">Plein écran</button></div><div class="erp-code-editor"><label><span>HTML sécurisé · ${String(t.html).split('\n').length} lignes</span><div class="erp-code-with-lines"><pre>${lineNumbers(t.html)}</pre><textarea id="template-html" spellcheck="false" oninput="PilozApp.setTemplate('html',this.value)">${e(t.html)}</textarea></div></label><label><span>CSS · ${String(t.css).split('\n').length} lignes</span><div class="erp-code-with-lines"><pre>${lineNumbers(t.css)}</pre><textarea id="template-css" spellcheck="false" oninput="PilozApp.setTemplate('css',this.value)">${e(t.css)}</textarea></div></label></div><details class="erp-syntax-preview"><summary>Aperçu avec coloration syntaxique</summary><pre>${highlightCode(t.html)}</pre></details><p>JavaScript, événements HTML, iframe et ressources distantes sont supprimés à la sauvegarde.</p></div>`;if(t.mode==='preview')return`<iframe class="erp-template-preview" sandbox="" srcdoc="${e('<style>'+sanitizeTemplate(t.html,t.css).css+'</style>'+sampleTemplate(sanitizeTemplate(t.html,t.css).html))}"></iframe>`;return`<div class="erp-visual-compose"><div class="erp-visual-editor" id="template-blocks">${(t.visual_schema?.blocks||[]).map((block,index)=>`<article draggable="true" data-index="${index}" ondragstart="PilozApp.dragTemplateBlock(${index})" ondragover="event.preventDefault()" ondrop="PilozApp.dropTemplateBlock(${index})"><span>⋮⋮</span><b>${e(block.label||block.type)}</b><button class="ic" onclick="PilozApp.removeTemplateBlock(${index})">×</button></article>`).join('')}</div><iframe class="erp-template-preview" sandbox="" title="Aperçu visuel" srcdoc="${e('<style>'+sanitizeTemplate(t.html,t.css).css+'</style>'+sampleTemplate(sanitizeTemplate(t.html,t.css).html))}"></iframe></div>`;}
 function highlightCode(code){return e(code).replace(/(&lt;\/?)([a-z0-9-]+)/gi,'<span class="tok-bracket">$1</span><span class="tok-tag">$2</span>').replace(/(\{\{[^}]+\}\})/g,'<span class="tok-var">$1</span>').replace(/([a-z-]+)=(&quot;[^&]*?&quot;)/gi,'<span class="tok-attr">$1</span>=<span class="tok-string">$2</span>');}
 function findTemplateCode(){const query=document.getElementById('template-code-search')?.value,area=document.getElementById('template-html');if(!query||!area)return;const start=area.value.toLowerCase().indexOf(query.toLowerCase(),area.selectionEnd);const index=start>=0?start:area.value.toLowerCase().indexOf(query.toLowerCase());if(index>=0){area.focus();area.setSelectionRange(index,index+query.length);}else notice('Texte introuvable.');}
 function toggleTemplateFullscreen(){document.querySelector('.erp-template-workspace')?.classList.toggle('fullscreen');}
 function sampleTemplate(html){return String(html||'').replaceAll('{{company.name}}','Entreprise Exemple').replaceAll('{{company.siret}}','123 456 789 00012').replaceAll('{{client.name}}','Client Exemple').replaceAll('{{client.address}}','1 rue de Paris, 75001 Paris').replaceAll('{{document.number}}','DEV-2026-0001').replaceAll('{{document.issue_date}}','20/07/2026').replaceAll('{{document.due_date}}','19/08/2026').replaceAll('{{document.total_ht}}','1 000,00 €').replaceAll('{{document.total_vat}}','200,00 €').replaceAll('{{document.total_ttc}}','1 200,00 €').replaceAll('{{document.payment_terms}}','30 jours').replaceAll('{{document.lines}}','<table><tr><td>Prestation</td><td>1</td><td>1 000,00 €</td></tr></table>').replaceAll('{{company.logo}}','');}
 function sanitizeTemplate(html,css){const doc=new DOMParser().parseFromString(String(html||''),'text/html');doc.querySelectorAll('script,iframe,object,embed,link,meta,base,form').forEach(node=>node.remove());doc.querySelectorAll('*').forEach(node=>[...node.attributes].forEach(attr=>{const name=attr.name.toLowerCase(),value=attr.value.trim().toLowerCase();if(name.startsWith('on')||['srcdoc'].includes(name)||(name==='style'&&/url\s*\(/i.test(value))||(['src','href'].includes(name)&&/^(javascript:|data:text\/html|https?:)/i.test(value)))node.removeAttribute(attr.name);}));const safeCss=String(css||'').replace(/@import[^;]+;?/gi,'').replace(/url\s*\([^)]*\)/gi,'').replace(/expression\s*\([^)]*\)/gi,'').replace(/<\/?style\b[^>]*>/gi,'').replace(/[<>]/g,'');return{html:doc.body.innerHTML,css:safeCss};}
 function setTemplate(field,value){state.templateDraft[field]=value;if(!['html','css'].includes(field))renderTemplateEditor();}
 function setTemplateMode(mode){state.templateDraft.mode=mode;renderTemplateEditor();}
 function templateBlockHtml(type,id){const content={entreprise:'<h2>{{company.name}}</h2><p>SIRET : {{company.siret}} · TVA : {{company.vat_number}}</p>',client:'<h2>{{client.name}}</h2><p>{{client.address}}</p>',document:'<h1>Document {{document.number}}</h1><p>{{document.issue_date}} · {{document.due_date}}</p>',commercial:'<p>Votre contact commercial</p>',articles:'{{document.lines}}',totaux:'<p>Total HT : <b>{{document.total_ht}}</b><br>TVA : <b>{{document.total_vat}}</b><br>Total TTC : <b>{{document.total_ttc}}</b></p>',paiement:'<p>{{document.payment_terms}}</p>',livraison:'<h3>Informations de livraison</h3>',contrat:'<h3>Conditions du contrat</h3>',stock:'<h3>Informations de disponibilité</h3>','champs personnalisés':'<p>Champ personnalisé</p>'};return`<section data-block="${e(type)}" data-block-id="${e(id)}">${content[type]||`<h3>${e(type)}</h3>`}</section>`;}
 function syncTemplateBlockOrder(){const doc=new DOMParser().parseFromString(state.templateDraft.html||'','text/html');for(const block of state.templateDraft.visual_schema.blocks||[]){const node=doc.querySelector(`[data-block-id="${CSS.escape(block.id||'')}"]`);if(node)doc.body.appendChild(node);}state.templateDraft.html=doc.body.innerHTML;}
 function addTemplateBlock(type){const id=uuid(),block={id,type,label:type};state.templateDraft.visual_schema.blocks.push(block);state.templateDraft.html+=templateBlockHtml(type,id);renderTemplateEditor();}
 function removeTemplateBlock(index){const [block]=state.templateDraft.visual_schema.blocks.splice(index,1),doc=new DOMParser().parseFromString(state.templateDraft.html||'','text/html');if(block?.id)doc.querySelector(`[data-block-id="${CSS.escape(block.id)}"]`)?.remove();state.templateDraft.html=doc.body.innerHTML;renderTemplateEditor();}
 function dragTemplateBlock(index){state.dragTemplateBlock=index;}
 function dropTemplateBlock(index){if(state.dragTemplateBlock==null||state.dragTemplateBlock===index)return;const blocks=state.templateDraft.visual_schema.blocks,[block]=blocks.splice(state.dragTemplateBlock,1);blocks.splice(index,0,block);state.dragTemplateBlock=null;syncTemplateBlockOrder();renderTemplateEditor();}
 function insertVariable(variable){state.templateDraft.html+=` {{${variable}}}`;state.templateDraft.mode='code';renderTemplateEditor();}
 function invalidTemplateVariables(html){const allowed=new Set(['company.name','company.logo','company.siret','company.vat_number','client.name','client.address','document.number','document.issue_date','document.due_date','document.total_ht','document.total_vat','document.total_ttc','document.lines','document.payment_terms']);return[...String(html||'').matchAll(/\{\{\s*([^}]+?)\s*\}\}/g)].map(match=>match[1]).filter(variable=>!allowed.has(variable));}
 async function saveTemplate(){const t=state.templateDraft,invalid=[...new Set(invalidTemplateVariables(t.html))];if(invalid.length){notice(`Variables inconnues : ${invalid.join(', ')}`,'error');return;}const safe=sanitizeTemplate(t.html,t.css);try{const result=await api().invoke('save-document-template',{companyId:state.companyId,templateId:t.templateId,name:t.name,documentType:t.document_type,language:t.language,status:t.status,isDefault:!!t.is_default,visualSchema:t.visual_schema,html:safe.html,css:safe.css,comment:'Enregistrement depuis l’éditeur'});await refresh();await editTemplate(result.templateId);notice('Nouvelle version du modèle enregistrée.','success');}catch(error){notice(error.message,'error');}}
 async function duplicateTemplate(id){await editTemplate(id);state.templateDraft.templateId=null;state.templateDraft.name+=' — copie';state.templateDraft.version=0;state.templateDraft.versions=[];renderTemplateEditor();}
 async function previewTemplate(id){await editTemplate(id);if(state.templateDraft){state.templateDraft.mode='preview';renderTemplateEditor();}}
 async function setTemplateStatus(id,value){try{await api().update('document_templates',id,{status:value,is_default:value==='active'?(state.data.templates||[]).find(x=>x.id===id)?.is_default:false});await refresh();notice('Statut du modèle mis à jour.','success');}catch(error){notice(error.message,'error');}}
 async function exportTemplate(id){await editTemplate(id);const t=state.templateDraft,blob=new Blob([JSON.stringify({format:'piloz-template-v1',name:t.name,document_type:t.document_type,language:t.language,visual_schema:t.visual_schema,html:t.html,css:t.css},null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=(t.name||'modele').replace(/[^a-z0-9_-]+/gi,'-')+'.json';link.click();URL.revokeObjectURL(url);go('templates');}
 async function importTemplate(file){if(!file)return;try{const data=JSON.parse(await file.text());if(data.format!=='piloz-template-v1')throw new Error('Format de modèle non reconnu.');state.templateDraft={...defaultTemplate(),name:data.name||'Modèle importé',document_type:data.document_type||'quote',language:data.language||'fr',visual_schema:data.visual_schema||{blocks:[]},html:data.html||'',css:data.css||''};go('template-editor');notice('Modèle importé. Vérifiez-le puis enregistrez une version.');}catch(error){notice(error.message,'error');}}
 async function restoreTemplateVersion(id){const version=(state.templateDraft.versions||[]).find(x=>x.id===id);if(!version)return;Object.assign(state.templateDraft,{visual_schema:structuredClone(version.visual_schema),html:version.html,css:version.css,mode:'preview'});renderTemplateEditor();notice('Version chargée. Enregistrez pour créer une nouvelle version restaurée.');}

 function renderReports(){const docs=state.data.documents||[],sales=docs.filter(x=>['invoice','quote'].includes(x.document_type)),byClient=new Map(),byItem=new Map();sales.forEach(doc=>{const name=doc.client?.legal_name||'Sans client',row=byClient.get(name)||{sales:0,cost:0};row.sales+=Number(doc.total_excl_tax);row.cost+=Number(doc.total_cost);byClient.set(name,row);});(state.data.lines||[]).forEach(line=>{if(!line.item_id)return;const item=(state.data.catalog||[]).find(x=>x.id===line.item_id),name=item?.name||line.name,row=byItem.get(name)||{sales:0,cost:0};row.sales+=Number(line.total_excl_tax);row.cost+=Number(line.quantity)*Number(line.unit_cost_snapshot);byItem.set(name,row);});document.getElementById('main').innerHTML=top('Rapports de marge et de stock')+`<div class="erp-grid-2"><section class="phase1-card"><h2>Marge par client</h2>${reportTable(byClient)}</section><section class="phase1-card"><h2>Marge par article</h2>${reportTable(byItem)}</section></div><section class="phase1-card"><h2>Historique des coûts</h2><div class="phase1-table-wrap"><table class="phase1-table"><tr><th>Date</th><th>Article</th><th>Ancien coût</th><th>Nouveau coût</th><th>Quantité reçue</th></tr>${(state.data.costHistory||[]).map(x=>`<tr><td>${date(x.created_at)}</td><td>${e((state.data.catalog||[]).find(i=>i.id===x.item_id)?.name||'—')}</td><td>${money(x.previous_cost)}</td><td>${money(x.new_cost)}</td><td>${x.quantity_received||'—'}</td></tr>`).join('')}</table></div></section>`;}
 function enhanceMarginReports(){const main=document.getElementById('main'),documents=new Map((state.data.documents||[]).map(doc=>[doc.id,doc])),byCategory=new Map(),bySalesperson=new Map(),byPeriod=new Map();for(const line of state.data.lines||[]){const doc=documents.get(line.document_id);if(!doc||!['quote','invoice'].includes(doc.document_type))continue;const item=(state.data.catalog||[]).find(x=>x.id===line.item_id),category=item?.category||'Sans catégorie',sales=Number(line.total_excl_tax)||0,cost=Number(line.quantity)*Number(line.unit_cost_snapshot),categoryRow=byCategory.get(category)||{sales:0,cost:0};categoryRow.sales+=sales;categoryRow.cost+=cost;byCategory.set(category,categoryRow);}for(const doc of state.data.documents||[]){if(!['quote','invoice'].includes(doc.document_type))continue;const salesperson=doc.assigned_user_id||'Non attribué',period=String(doc.issue_date||'').slice(0,7)||'Sans date';for(const [map,key] of [[bySalesperson,salesperson],[byPeriod,period]]){const row=map.get(key)||{sales:0,cost:0};row.sales+=Number(doc.total_excl_tax);row.cost+=Number(doc.total_cost);map.set(key,row);}}const section=document.createElement('div');section.className='erp-grid-2';section.innerHTML=`<section class="phase1-card"><h2>Marge par catégorie</h2>${reportTable(byCategory)}</section><section class="phase1-card"><h2>Marge par commercial</h2>${reportTable(bySalesperson)}</section><section class="phase1-card"><h2>Marge par période</h2>${reportTable(byPeriod)}</section>`;main.appendChild(section);}
 const renderReportsBase=renderReports;renderReports=function(){if(!allowed('view_margins')){document.getElementById('main').innerHTML=top('Rapports')+empty('Accès restreint','Votre rôle ne permet pas de consulter les marges.');return;}renderReportsBase();enhanceMarginReports();};
 function reportTable(map){return`<table class="phase1-table"><tr><th>Élément</th><th>Ventes HT</th><th>Coût historique</th><th>Marge</th></tr>${[...map].sort((a,b)=>b[1].sales-a[1].sales).map(([name,row])=>`<tr><td>${e(name)}</td><td>${money(row.sales)}</td><td>${money(row.cost)}</td><td><b>${money(row.sales-row.cost)}</b></td></tr>`).join('')}</table>`;}

 function renderSettings(){const s=state.data.settings?.[0]||{};document.getElementById('main').innerHTML=top('Paramètres de l’entreprise',button('Enregistrer','PilozApp.saveSettings()','btn-p'))+`<div class="erp-settings-layout"><aside class="phase1-settings-nav"><h2>Mon entreprise</h2><a href="#settings-company">Identité</a><a href="#settings-address">Adresse</a><a href="#settings-contact">Coordonnées</a><a href="#settings-logo">Logo</a><a href="#settings-tax">Fiscalité</a><h2>Documents</h2><a href="#settings-documents">Numérotation</a><a href="#templates">Modèles</a><h2>Catalogue & stock</h2><a href="#sales/catalog">Articles</a><a href="#stock/warehouses">Entrepôts</a><a href="#purchases/suppliers">Fournisseurs</a></aside><form id="company-settings-form" class="erp-settings-content" onsubmit="return false"><section id="settings-company" class="phase1-card"><h2>Identité et informations légales</h2><div class="phase1-grid">${field('Raison sociale *','legal_name',s.legal_name,'text','required')}${field('Nom commercial','trade_name',s.trade_name)}${field('Forme juridique *','legal_form',s.legal_form,'text','required')}${field('SIREN','siren',s.siren)}${field('SIRET *','siret',s.siret,'text','required')}${field('Code APE / NAF','ape_code',s.ape_code)}${field('Activité principale','activity',s.activity)}${field('Date de création','creation_date',s.creation_date,'date')}${field('Site internet','website',s.website,'url')}<p class="phase1-note full">Source : ${e(s.data_source||'Saisie manuelle')} · Récupération : ${date(s.data_retrieved_at)}</p></div></section><section id="settings-address" class="phase1-card"><h2>Adresse</h2><div class="phase1-grid"><div class="phase1-field full"><span>Recherche prédictive</span><input id="settings-address-search" placeholder="Commencez à saisir une adresse" oninput="PilozApp.searchAddress(this.value)"><div id="settings-address-results" class="phase1-search-results"></div></div>${field('Adresse','address_line1',s.address_line1)}${field('Complément','address_line2',s.address_line2)}${field('Code postal','postal_code',s.postal_code)}${field('Ville','city',s.city)}${field('Code pays','country_code',s.country_code||'FR')}</div></section><section id="settings-contact" class="phase1-card"><h2>Coordonnées</h2><div class="phase1-grid">${field('E-mail professionnel','email',s.email,'email')}${field('Téléphone professionnel','phone',s.phone||s.phone_e164,'tel')}<div><span>${s.email_confirmed_at?'E-mail confirmé le '+date(s.email_confirmed_at):'E-mail non confirmé'}</span>${!s.email_confirmed_at?button('Envoyer la confirmation','PilozApp.requestEmailConfirmation()'):''}</div><div><span>${s.phone_verified_at?'Téléphone vérifié':'Téléphone non vérifié — aucun SMS simulé'}</span></div></div></section><section id="settings-logo" class="phase1-card"><h2>Identité visuelle</h2><div class="erp-logo-upload"><label class="erp-dropzone">Logo clair<input type="file" accept="image/png,image/jpeg,image/svg+xml" onchange="PilozApp.uploadLogo(this.files[0],'light')"></label><label class="erp-dropzone">Logo sombre<input type="file" accept="image/png,image/jpeg,image/svg+xml" onchange="PilozApp.uploadLogo(this.files[0],'dark')"></label></div><p>PNG, JPEG ou SVG sécurisé, 5 Mo maximum. Les logos sont stockés dans un bucket privé isolé par entreprise.</p></section><section id="settings-tax" class="phase1-card"><h2>Fiscalité</h2><div class="phase1-grid"><label class="phase1-field"><span>Assujettie à la TVA</span><select name="subject_to_vat"><option value="false" ${s.subject_to_vat===false?'selected':''}>Non</option><option value="true" ${s.subject_to_vat?'selected':''}>Oui</option></select></label>${field('N° TVA intracommunautaire','vat_number',s.vat_number)}${field('Régime de TVA','vat_regime',s.vat_regime)}${field('Taux de TVA par défaut','default_vat_rate',s.default_vat_rate??20,'number','step="0.01"')}${field('Devise','currency',s.currency||'EUR')}${field('Langue','language',s.language||'fr')}</div></section><section id="settings-documents" class="phase1-card"><h2>Documents et numérotation</h2><p>Les numéros définitifs sont attribués par transaction SQL avec verrou de ligne. Configurez les préfixes dans la table des séquences.</p><div class="erp-doc-examples"><code>DEV-${new Date().getFullYear()}-0001</code><code>FAC-${new Date().getFullYear()}-0001</code><code>AV-${new Date().getFullYear()}-0001</code></div></section></form></div>`;}
 async function saveSettings(){const form=document.getElementById('company-settings-form'),data=Object.fromEntries(new FormData(form));data.subject_to_vat=data.subject_to_vat==='true';data.default_vat_rate=Number(data.default_vat_rate)||0;data.email=String(data.email||'').trim().toLowerCase();const normalizedPhone=calc().e164(data.phone,'FR');if(data.phone&&!normalizedPhone){notice('Numéro de téléphone invalide.','error');return;}data.phone_e164=normalizedPhone;delete data.phone;if(data.siret&&!calc().validSiren(data.siret)){notice('SIRET invalide.','error');return;}try{await api().upsertCompanySettings(state.companyId,data);await refresh();notice('Paramètres enregistrés.','success');}catch(error){notice(error.message,'error');}}
 let addressTimer=null,addressController=null;
 function searchAddress(value){clearTimeout(addressTimer);addressController?.abort();const q=value.trim();if(q.length<3){renderAddressResults([]);return;}addressTimer=setTimeout(async()=>{addressController=new AbortController();try{const data=await api().invoke('address-search',{query:q},addressController.signal);renderAddressResults(data.results||[]);}catch(error){if(error.name!=='AbortError')notice(error.message,'error');}},300);}
 function renderAddressResults(results){const node=document.getElementById('settings-address-results');if(!node)return;global.__pilozAddressResults=results;node.innerHTML=results.map((x,index)=>`<button type="button" onclick="PilozApp.selectAddress(${index})"><b>${e(x.label)}</b><small>${e([x.postalCode,x.city].filter(Boolean).join(' '))}</small></button>`).join('');}
 function selectAddress(index){const x=global.__pilozAddressResults?.[index],form=document.getElementById('company-settings-form');if(!x||!form)return;['address_line1','address_line2','postal_code','city','country_code'].forEach(name=>{const mapping={address_line1:'addressLine1',address_line2:'addressLine2',postal_code:'postalCode',city:'city',country_code:'countryCode'};form.elements[name].value=x[mapping[name]]||'';});renderAddressResults([]);}
