 function enhancePhoneVerification(){const section=document.getElementById('settings-contact');if(section&&!section.querySelector('[data-phone-verify]')&&!state.data.settings?.[0]?.phone_verified_at){const buttonNode=document.createElement('button');buttonNode.type='button';buttonNode.className='btn btn-o';buttonNode.dataset.phoneVerify='';buttonNode.textContent='Vérifier par SMS';buttonNode.onclick=requestPhoneVerification;section.appendChild(buttonNode);}const content=document.querySelector('.erp-settings-content');if(content&&!document.getElementById('settings-users')){const card=document.createElement('section');card.id='settings-users';card.className='phase1-card';card.innerHTML=`<h2>Utilisateurs, rôles et permissions</h2><div class="phase1-table-wrap"><table class="phase1-table"><tr><th>Utilisateur</th><th>Rôle</th><th>Prix d’achat</th><th>Marges</th><th>Ajustements stock</th></tr>${(state.data.members||[]).map(member=>{const p=member.permissions||{};return`<tr><td class="phase1-mono">${e(member.user_id)}</td><td><select onchange="PilozApp.updateMember('${member.user_id}','role',this.value)" ${member.role==='owner'?'disabled':''}><option value="member">Membre</option><option value="admin" ${member.role==='admin'?'selected':''}>Administrateur</option><option value="owner" ${member.role==='owner'?'selected':''}>Propriétaire</option></select></td>${['view_purchase_prices','view_margins','adjust_stock'].map(key=>`<td><input type="checkbox" ${p[key]?'checked':''} onchange="PilozApp.updateMember('${member.user_id}','${key}',this.checked)"></td>`).join('')}</tr>`;}).join('')}</table></div></section>`;content.appendChild(card);}}
 async function updateMember(userId,key,value){const member=(state.data.members||[]).find(x=>x.user_id===userId);if(!member)return;const data=key==='role'?{role:value}:{permissions:{...(member.permissions||{}),[key]:value}};try{await api().request(`/rest/v1/company_members?company_id=eq.${state.companyId}&user_id=eq.${userId}`,{method:'PATCH',body:JSON.stringify(data)});await refresh();notice('Permissions enregistrées.','success');}catch(error){notice(error.message,'error');}}
 async function requestPhoneVerification(){const raw=document.querySelector('#company-settings-form [name="phone"]')?.value,phone=calc().e164(raw,'FR');if(!phone){notice('Numéro de téléphone invalide.','error');return;}try{await api().invoke('request-company-phone-verification',{companyId:state.companyId,phone});modal('Code de vérification',`<form id="phone-code-form">${field('Code reçu par SMS','code','','text','inputmode="numeric" maxlength="6"')}</form>`,button('Annuler','PilozApp.closeModal()')+button('Confirmer','PilozApp.confirmPhone()','btn-p'));}catch(error){notice(error.message,'error');}}
