 async function uploadLogo(file,variant){if(!file)return;if(!['image/png','image/jpeg','image/svg+xml'].includes(file.type)||file.size>5242880){notice('Fichier refusé : type ou taille incorrecte.','error');return;}let upload=file;if(file.type==='image/svg+xml'){const text=await file.text(),doc=new DOMParser().parseFromString(text,'image/svg+xml');doc.querySelectorAll('script,foreignObject,iframe,object,embed').forEach(x=>x.remove());doc.querySelectorAll('*').forEach(node=>[...node.attributes].forEach(attr=>{if(attr.name.toLowerCase().startsWith('on')||/^(javascript:|https?:)/i.test(attr.value))node.removeAttribute(attr.name);}));upload=new File([new XMLSerializer().serializeToString(doc)],file.name,{type:file.type});}const ext=file.type==='image/png'?'png':file.type==='image/jpeg'?'jpg':'svg',path=`${state.companyId}/logos/${variant}-${Date.now()}.${ext}`;try{await api().upload('company-assets',path,upload);await api().request(`/rest/v1/company_logos?company_id=eq.${state.companyId}&variant=eq.${variant}&is_active=eq.true`,{method:'PATCH',body:JSON.stringify({is_active:false})});await api().insert('company_logos',{company_id:state.companyId,variant,storage_path:path,mime_type:file.type,size_bytes:upload.size});notice('Logo enregistré.','success');}catch(error){notice(error.message,'error');}}

 function enhanceExtendedSettings(){const content=document.querySelector('.erp-settings-content'),nav=document.querySelector('.phase1-settings-nav');if(!content||document.getElementById('settings-erp'))return;const docs=state.data.docSettings?.[0]||{},erp=state.data.erpSettings?.[0]||{},year=new Date().getFullYear(),types=[['quote','Devis','DEV'],['invoice','Factures','FAC'],['credit_note','Avoirs','AV'],['sales_order','Commandes','CMD'],['delivery_note','Livraisons','BL'],['purchase_order','Achats','BCF'],['contract','Contrats','CTR']],sequences=types.map(([type,label,prefix])=>{const sequence=(state.data.sequences||[]).find(x=>x.document_type===type&&Number(x.year)===year)||{};return`<tr><td>${label}</td><td><input data-sequence-prefix="${type}" value="${e(sequence.prefix||prefix)}"></td><td><input data-sequence-next="${type}" type="number" min="1" value="${Number(sequence.next_value)||1}"></td><td><code>${e(sequence.prefix||prefix)}-${year}-${String(Number(sequence.next_value)||1).padStart(4,'0')}</code></td></tr>`;}).join('');content.insertAdjacentHTML('beforeend',`<section id="settings-bank" class="phase1-card"><h2>Banque et paiements</h2><div class="phase1-grid"><label class="phase1-field"><span>Titulaire</span><input id="ext-bank-holder" value="${e(docs.bank_account_holder||'')}"></label><label class="phase1-field"><span>Banque</span><input id="ext-bank-name" value="${e(docs.bank_name||'')}"></label><label class="phase1-field"><span>IBAN</span><input id="ext-iban" value="${e(docs.iban||'')}"></label><label class="phase1-field"><span>BIC</span><input id="ext-bic" value="${e(docs.bic||'')}"></label></div></section><section id="settings-sequences" class="phase1-card"><h2>Numérotation</h2><div class="phase1-table-wrap"><table class="phase1-table"><tr><th>Document</th><th>Préfixe</th><th>Prochain numéro</th><th>Exemple</th></tr>${sequences}</table></div></section><section id="settings-document-rules" class="phase1-card"><h2>Règles documentaires</h2><div class="phase1-grid"><label class="phase1-field"><span>Validité des devis (jours)</span><input id="ext-quote-validity" type="number" min="1" value="${Number(docs.quote_validity_days)||30}"></label><label class="phase1-field"><span>Conditions de paiement</span><input id="ext-payment-terms" value="${e(docs.default_payment_terms||'30 jours')}"></label><label class="phase1-field"><span>Mode de paiement par défaut</span><input id="ext-payment-method" value="${e(docs.default_payment_method||'Virement bancaire')}"></label><label class="phase1-field"><span>Moyens acceptés (séparés par une virgule)</span><input id="ext-payment-methods" value="${e((docs.accepted_payment_methods||[]).join(', '))}"></label><label class="phase1-field"><span>Langue des documents</span><input id="ext-document-language" value="${e(docs.document_language||'fr')}"></label><label class="phase1-field full"><span>Mentions légales</span><textarea id="ext-legal-notice">${e(docs.legal_notice||'')}</textarea></label></div></section><section id="settings-erp" class="phase1-card"><h2>Catalogue, stock et achats</h2><div class="phase1-grid"><label class="phase1-field"><span>Méthode de valorisation</span><select id="ext-valuation"><option value="weighted_average">Coût moyen pondéré</option><option value="fifo" ${erp.valuation_method==='fifo'?'selected':''}>FIFO (préparé)</option><option value="standard" ${erp.valuation_method==='standard'?'selected':''}>Coût standard (préparé)</option><option value="last_purchase" ${erp.valuation_method==='last_purchase'?'selected':''}>Dernier achat (préparé)</option></select></label><label class="phase1-check"><input id="ext-negative-stock" type="checkbox" ${erp.allow_negative_stock?'checked':''}><span>Autoriser le stock négatif</span></label><label class="phase1-field"><span>Tolérance de réception (%)</span><input id="ext-receipt-tolerance" type="number" min="0" max="100" step="0.01" value="${Number(erp.receipt_tolerance_percent)||0}"></label><label class="phase1-field"><span>Horizon de réapprovisionnement (jours)</span><input id="ext-replenishment-horizon" type="number" min="1" max="365" value="${Number(erp.replenishment_horizon_days)||30}"></label><label class="phase1-field"><span>Conditions fournisseurs</span><input id="ext-supplier-terms" value="${e(erp.default_supplier_terms||'')}"></label></div></section>`);if(nav)nav.insertAdjacentHTML('beforeend','<h2>Configuration ERP</h2><a href="#settings-bank">Banque</a><a href="#settings-sequences">Numérotation</a><a href="#settings-document-rules">Documents</a><a href="#settings-erp">Catalogue · Stock · Achats</a><a href="#settings-users">Utilisateurs et permissions</a>');}
 function enhanceLogoSettings(){const section=document.getElementById('settings-logo');if(!section||section.querySelector('.erp-logo-current'))return;const current=document.createElement('div');current.className='erp-logo-current';current.innerHTML=['light','dark'].map(variant=>{const logo=(state.data.logos||[]).find(x=>x.variant===variant),url=state.data.logoUrls?.[variant];return`<article><h3>Logo ${variant==='light'?'clair':'sombre'}</h3>${logo&&url?`<img src="${e(url)}" alt="Aperçu du logo ${variant}"><button type="button" class="btn btn-ghost" onclick="PilozApp.removeLogo('${logo.id}','${e(logo.storage_path)}')">Supprimer</button>`:'<p>Aucun logo actif.</p>'}</article>`;}).join('');section.insertBefore(current,section.querySelector('.erp-logo-upload'));}
