 const renderSettingsBase=renderSettings;renderSettings=function(){renderSettingsBase();setTimeout(()=>{enhanceLogoSettings();enhanceExtendedSettings();},0);};
 const saveSettingsBase=saveSettings;saveSettings=async function(){const read=id=>document.getElementById(id)?.value,docPayload={company_id:state.companyId,bank_account_holder:read('ext-bank-holder')||null,bank_name:read('ext-bank-name')||null,iban:read('ext-iban')||null,bic:read('ext-bic')||null,quote_validity_days:Number(read('ext-quote-validity'))||30,default_payment_terms:read('ext-payment-terms')||null,default_payment_method:read('ext-payment-method')||null,accepted_payment_methods:String(read('ext-payment-methods')||'').split(',').map(x=>x.trim()).filter(Boolean),document_language:read('ext-document-language')||'fr',legal_notice:read('ext-legal-notice')||null},erpPayload={company_id:state.companyId,valuation_method:read('ext-valuation')||'weighted_average',allow_negative_stock:!!document.getElementById('ext-negative-stock')?.checked,receipt_tolerance_percent:Number(read('ext-receipt-tolerance'))||0,replenishment_horizon_days:Number(read('ext-replenishment-horizon'))||30,default_supplier_terms:read('ext-supplier-terms')||null},sequencePayload=[...document.querySelectorAll('[data-sequence-prefix]')].map(input=>({company_id:state.companyId,document_type:input.dataset.sequencePrefix,prefix:input.value.trim().toUpperCase(),year:new Date().getFullYear(),next_value:Number(document.querySelector(`[data-sequence-next="${input.dataset.sequencePrefix}"]`)?.value)||1}));await saveSettingsBase();try{await api().request('/rest/v1/company_document_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(docPayload)});await api().request('/rest/v1/company_erp_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(erpPayload)});if(sequencePayload.length)await api().request('/rest/v1/document_sequences?on_conflict=company_id,document_type,year',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(sequencePayload)});await refresh();notice('Tous les paramètres ERP sont enregistrés.','success');}catch(error){notice(error.message,'error');}};

 async function processEmailConfirmation(){const params=new URLSearchParams(location.search),token=params.get('verify_company_email'),companyId=params.get('company');if(!token||!companyId||!global.PilozRuntime?.session)return;try{await api().invoke('confirm-company-email',{token,companyId});params.delete('verify_company_email');params.delete('company');history.replaceState(null,'',location.pathname+(params.toString()?'?'+params:'')+location.hash);notice('E-mail professionnel confirmé.','success');}catch(error){notice(error.message,'error');}}

